=El usuario env├¡a el siguiente mensaje:

Nombre_usuario: {{ $('WhatsApp Trigger').first().json.body.data.pushName }}
Mensaje del usuario: {{ $('Fields').first().json.Message_text }}

Id: {{ $('WhatsApp Trigger').first().json.body.data.key.remoteJid }}

INSTRUCCION OBLIGATORIA: Antes de responder cualquier mensaje que mencione una pizza, comida o pedido, ejecut├í la tool "menu" primero. Sin excepci├│n.

parameters.jsCode:
const texto = $input.first().json.output || "";
const limpio = texto.replace(/┬┐/g, "").trim();

// Si contiene una lista numerada, NO dividir ÔÇö mandarlo completo
if (/\d+[\.\-]/.test(limpio)) {
  return [{ json: { output: { response: { 
    part_1: limpio, part_2: "", part_3: "", part_4: "" 
  } } } }];
}

// Si es corto, todo en part_1
if (limpio.length <= 100) {
  return [{ json: { output: { response: { 
    part_1: limpio, part_2: "", part_3: "", part_4: "" 
  } } } }];
}

// Dividir solo por punto/pregunta seguido de may├║scula
const oraciones = limpio
  .split(/(?<=[.?])\s+(?=[A-Z├ü├ë├ì├ô├Ü├æ])/)
  .map(s => s.trim())
  .filter(s => s.length > 0);

const partes = ["", "", "", ""];
for (let i = 0; i < Math.min(2, oraciones.length); i++) {
  partes[i] = oraciones[i];
}

return [{ json: { output: { response: { 
  part_1: partes[0], part_2: partes[1], part_3: partes[2], part_4: partes[3] 
} } } }];

